  const hpFolder = current;
  const files = [{"name":"faq.html","mimeType":"text/html","content":"      <section class=\"mt-32 pt-12 border-t border-gray-100\">\n        <h2 class=\"text-xl md:text-2xl font-bold text-gray-400 mb-12 flex items-center\">\n          ５．よくあるお問合せ\n        </h2>\n        \n        <div class=\"space-y-12\">\n          <div class=\"border-b border-gray-100 pb-12\">\n            <h3 class=\"font-bold text-lg text-gray-800 flex items-start mb-6\">\n              <span class=\"text-shutoko-green mr-4 text-xl font-black italic\">Q3.</span>\n              <span class=\"mt-0.5 leading-snug\">近接協議には費用がかかりますか。</span>\n            </h3>\n            <div class=\"text-gray-600 text-sm md:text-base leading-loose pl-10\">\n              <p class=\"mb-8\">弊社との協議自体は、一般的な範囲については原則無償で対応いたします。ただし、仮設費用、交通規制に関する費用、高速道路構造物の保護に要する費用などは協議者負担となります。</p>\n              \n              <div class=\"border border-gray-200 rounded-lg overflow-hidden bg-white shadow-sm\">\n                <div class=\"bg-gray-50 py-3 px-6 border-b border-gray-200\">\n                  <p class=\"font-bold text-gray-600 text-xs tracking-widest\">技術的支援（有償）をご希望の場合</p>\n                </div>\n                <div class=\"p-6 md:p-8\">\n                  <p class=\"mb-6 text-gray-700 leading-relaxed text-sm md:text-base\">\n                    高度な技術的支援を弊社<span class=\"font-bold text-gray-900 border-b border-gray-300\">海外・社会インフラ部</span>に依頼する場合は、別途費用が発生します。\n                  </p>\n                  \n                  <div class=\"bg-gray-50 p-6 rounded border border-gray-200\">\n                    <p class=\"font-bold text-gray-800 text-sm mb-1\">海外・社会インフラ部 技術事業企画課</p>\n                    <p class=\"text-xl md:text-2xl font-bold text-shutoko-navy mb-4 tracking-tight\">TEL．03-3539-9356</p>\n                    \n                    <div class=\"mt-4 p-4 bg-white border border-shutoko-accent/20 rounded text-xs leading-relaxed\">\n                      <p class=\"text-shutoko-accent font-bold mb-1 flex items-center\">\n                        <svg class=\"w-4 h-4 mr-2\" fill=\"currentColor\" viewBox=\"0 0 20 20\"><path fill-rule=\"evenodd\" d=\"M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z\" clip-rule=\"evenodd\"></path></svg>\n                        ご案内\n                      </p>\n                      <p class=\"text-gray-500\">\n                        こちらの番号は<span class=\"font-bold text-gray-700\">「有償支援の専用窓口」</span>です。通常の申請や進捗確認は、ページ上部のWEBフォームをご利用ください。\n                      </p>\n                    </div>\n                  </div>\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>\n"},{"name":"footer.html","mimeType":"text/html","content":"    </div>\n  </main>\n  \n  <footer class=\"bg-gray-50 border-t border-gray-200 py-16\">\n    <div class=\"max-w-5xl mx-auto px-4 text-center\">\n      <div class=\"flex flex-wrap justify-center gap-x-8 gap-y-4 mb-8 text-xs font-bold text-gray-500\">\n        <a href=\"#\" class=\"hover:text-shutoko-green\">企業情報</a>\n        <a href=\"#\" class=\"hover:text-shutoko-green\">IR情報</a>\n        <a href=\"#\" class=\"hover:text-shutoko-green text-shutoko-green\">法人向け情報</a>\n        <a href=\"#\" class=\"hover:text-shutoko-green\">採用情報</a>\n        <a href=\"#\" class=\"hover:text-shutoko-green\">サイトマップ</a>\n      </div>\n      <p class=\"text-[10px] text-gray-400 tracking-[0.1em]\">©Metropolitan Expressway Company Limited.</p>\n    </div>\n  </footer>\n\n</body>\n</html>\n"},{"name":"guidance.html","mimeType":"text/html","content":"      <section>\n        <h2 class=\"text-xl md:text-2xl font-bold text-gray-900 heading-l3 mb-8\">１．近接協議が必要となる工事や作業とは</h2>\n        <p class=\"mb-8 text-gray-700 leading-loose text-sm md:text-base text-justify\">\n          首都高速道路に近接して行なわれる工事や作業のうち、以下のような首都高速道路の構造物（高架下のフェンス等の弊社管理物を含みます。）及び出入口を含む首都高速道路上の交通に影響を与える可能性のあるもの（「近接施工」といいます。）については近接協議をお願いしています。\n        </p>\n        <div class=\"bg-white p-7 md:p-10 rounded border border-gray-200 shadow-sm\">\n          <p class=\"font-bold text-sm text-shutoko-dark mb-6 tracking-widest flex items-center\">\n            <span class=\"w-8 h-px bg-shutoko-green mr-3\"></span>具体的な作業の例\n          </p>\n          <ul class=\"grid md:grid-cols-2 gap-y-4 gap-x-8 text-gray-700 text-sm md:text-base\">\n            <li class=\"flex items-start\"><span class=\"text-shutoko-green mr-3\">●</span>（1）建物の新築、改築、解体、修繕</li>\n            <li class=\"flex items-start\"><span class=\"text-shutoko-green mr-3\">●</span>（2）道路・橋梁等の点検、補修等</li>\n            <li class=\"flex items-start\"><span class=\"text-shutoko-green mr-3\">●</span>（3）宅地造成等に伴う盛土・切土</li>\n            <li class=\"flex items-start\"><span class=\"text-shutoko-green mr-3\">●</span>（4）電柱・架線の新設、撤去等</li>\n            <li class=\"flex items-start\"><span class=\"text-shutoko-green mr-3\">●</span>（5）地下埋設管の新設・撤去等</li>\n            <li class=\"flex items-start\"><span class=\"text-shutoko-green mr-3\">●</span>（6）トンネル上部で行う作業</li>\n          </ul>\n        </div>\n      </section>\n\n      <section>\n        <h2 class=\"text-xl md:text-2xl font-bold text-gray-900 heading-l3 mb-8\">２．工事着手までの流れ</h2>\n        <div class=\"bg-[#FFFDF5] border border-[#E9E1C1] p-6 rounded-md flex items-center shadow-sm\">\n          <p class=\"text-gray-800 font-bold leading-relaxed text-sm md:text-base\">\n            <span class=\"text-shutoko-accent mr-1\">※</span>\n            WEB問合せから協議回答までに<span class=\"border-b-2 border-shutoko-accent/30 mx-1\">通常2～3ヶ月程度の期間</span>を要し、内容次第では更に時間を要する場合もあります。余裕を持ってお問い合わせください。\n          </p>\n        </div>\n      </section>\n\n      <section>\n        <h2 class=\"text-xl md:text-2xl font-bold text-gray-900 heading-l3 mb-10\">３．近接協議の種類</h2>\n        <div class=\"space-y-12\">\n          <div class=\"group\">\n            <h3 class=\"font-bold text-lg text-shutoko-dark mb-3 flex items-center\">\n              <span class=\"w-2 h-2 bg-shutoko-green mr-3 rotate-45\"></span>（1）計画協議\n            </h3>\n            <p class=\"text-sm md:text-base text-gray-600 leading-loose pl-5\">計画の概要を示していただき、既設構造物に対する保全や将来の新線計画等に対する整合性が図れているかを確認します。</p>\n          </div>\n          <div class=\"group\">\n            <h3 class=\"font-bold text-lg text-shutoko-dark mb-3 flex items-center\">\n              <span class=\"w-2 h-2 bg-shutoko-green mr-3 rotate-45\"></span>（2）設計協議\n            </h3>\n            <p class=\"text-sm md:text-base text-gray-600 leading-loose pl-5\">既設構造物に対する詳細な影響検討を行い、将来的に支障のないことを確認します。検討結果次第では対策工を講じていただくことがあります。</p>\n          </div>\n          <div class=\"group\">\n            <h3 class=\"font-bold text-lg text-shutoko-dark mb-3 flex items-center\">\n              <span class=\"w-2 h-2 bg-shutoko-green mr-3 rotate-45\"></span>（3）施工協議\n            </h3>\n            <p class=\"text-sm md:text-base text-gray-600 leading-loose pl-5\">具体的な工事方法や詳細な工程についての検討を行います。必要に応じて、現場監督等についての条件を付すことがあります。</p>\n          </div>\n        </div>\n      </section>\n\n      <section class=\"mt-32 pt-16 border-t-2 border-gray-100\">\n        <h2 class=\"text-xl md:text-2xl font-bold text-gray-900 heading-l3 mb-10\">４．近接施工お問合せフォーム（WEB受付）</h2>\n        \n        <p class=\"mb-12 text-gray-700 leading-loose text-sm md:text-base\">\n          必要事項をご記入いただき、作業場所や内容が分かる資料を添付のうえ、WEB問合せをお願いします。<br>\n          <span class=\"text-shutoko-accent font-bold\">なお、このWEB問合せをもって近接施工の実施を了承するものではありません。</span>工事内容に応じて、別途、近接協議に係る手続きが必要となります。\n        </p>\n\n        <div class=\"bg-gray-50 p-8 md:p-16 text-center border border-gray-200 rounded-lg shadow-sm hover-arrow\">\n          <p class=\"text-sm md:text-base font-bold text-gray-700 mb-10 tracking-tight\">\n            ※上記「１～３」の内容をご確認いただけましたでしょうか。\n          </p>\n          <a href=\"https://krs.bz/shutokoweb/m?f=1920\" target=\"_blank\" class=\"btn-transition inline-flex items-center justify-center bg-shutoko-navy hover:bg-shutoko-dark text-white font-bold text-base md:text-lg py-5 px-10 md:px-14 rounded shadow-lg hover:shadow-xl w-full md:w-auto min-w-[340px]\">\n            上記の内容を確認のうえ、WEB問合せフォームへ進む\n            <svg class=\"w-5 h-5 ml-4\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"3\" d=\"M14 5l7 7m0 0l-7 7m7-7H3\"></path></svg>\n          </a>\n          <p class=\"text-xs text-gray-400 mt-6 tracking-wide italic\">（別ウィンドウで受付システムが開きます）</p>\n        </div>\n      </section>\n"},{"name":"header.html","mimeType":"text/html","content":"<!DOCTYPE html>\n<html lang=\"ja\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>近接施工のご案内｜法人向け情報｜首都高速道路株式会社</title>\n  <script src=\"https://cdn.tailwindcss.com\"></script>\n  <script>\n    tailwind.config = {\n      theme: {\n        extend: {\n          colors: {\n            shutoko: {\n              green: '#006B3F', /* 首都高グリーン */\n              dark: '#004D2D',\n              navy: '#1A365D', /* 落ち着いたネイビー（新ボタンカラー） */\n              light: '#F4F7F5', /* 非常に淡いグリーン背景 */\n              accent: '#C53030' /* 落ち着いた赤 */\n            }\n          }\n        }\n      }\n    }\n  </script>\n  <style>\n    body { font-family: \"ヒラギノ角ゴ ProN W3\", \"Hiragino Kaku Gothic ProN\", \"メイリオ\", Meiryo, sans-serif; -webkit-font-smoothing: antialiased; }\n    \n    .heading-l2 {\n      border-left: 6px solid #006B3F;\n      padding-left: 16px;\n      letter-spacing: 0.05em;\n    }\n    \n    .heading-l3 {\n      border-bottom: 2px solid #006B3F;\n      padding-bottom: 12px;\n      position: relative;\n    }\n    .heading-l3::after {\n      content: '';\n      position: absolute;\n      bottom: -2px;\n      left: 0;\n      width: 40px;\n      height: 2px;\n      background-color: #006B3F;\n    }\n\n    /* 緩やかなアニメーション */\n    .btn-transition {\n      transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);\n    }\n    \n    @keyframes slide-right {\n      0%, 100% { transform: translateX(0); }\n      50% { transform: translateX(6px); }\n    }\n    .hover-arrow:hover svg {\n      animation: slide-right 1s ease-in-out infinite;\n    }\n  </style>\n</head>\n<body class=\"bg-white text-gray-900 leading-relaxed\">\n\n  <header class=\"bg-white border-b-4 border-shutoko-green sticky top-0 z-50 shadow-sm\">\n    <div class=\"max-w-5xl mx-auto px-4 py-4 flex justify-between items-end\">\n      <div>\n        <div class=\"text-[10px] text-gray-400 mb-1 tracking-tight\">Metropolitan Expressway Company Limited.</div>\n        <div class=\"text-xl md:text-2xl font-bold tracking-widest text-black\">首都高速道路株式会社</div>\n      </div>\n      <nav class=\"hidden lg:flex space-x-8 text-sm font-bold text-gray-600 pb-1\">\n        <a href=\"#\" class=\"hover:text-shutoko-green\">企業情報</a>\n        <a href=\"#\" class=\"hover:text-shutoko-green\">IR情報</a>\n        <a href=\"#\" class=\"hover:text-shutoko-green\">首都高の取り組み</a>\n        <a href=\"#\" class=\"text-shutoko-green border-b-2 border-shutoko-green pb-1\">法人向け情報</a>\n        <a href=\"#\" class=\"hover:text-shutoko-green\">採用情報</a>\n      </nav>\n    </div>\n  </header>\n\n  <main class=\"max-w-4xl mx-auto px-6 py-12 md:py-16\">\n\n    <div class=\"text-[11px] text-gray-500 mb-10 flex items-center space-x-2\">\n      <a href=\"#\" class=\"hover:underline\">HOME</a> \n      <span>&gt;</span>\n      <a href=\"#\" class=\"hover:underline\">法人向け情報</a>\n      <span>&gt;</span>\n      <span class=\"text-gray-800 font-medium\">近接施工のご案内</span>\n    </div>\n\n    <div class=\"mb-12\">\n      <div class=\"mb-2 text-shutoko-green font-bold text-xs tracking-wider\">法人向け情報</div>\n      <div class=\"mb-6 text-gray-400 text-[9px] tracking-[0.2em] uppercase\">For Corporate</div>\n      <h1 class=\"text-3xl md:text-4xl font-bold text-gray-900 heading-l2 leading-tight\">近接施工のご案内</h1>\n    </div>\n    \n    <div class=\"bg-gray-50 p-5 mb-10 text-center text-sm md:text-base font-bold text-gray-700 border-y border-gray-200 tracking-wide\">\n      首都高速道路に近接して実施する工事等に関するご案内\n    </div>\n\n    <p class=\"text-gray-700 mb-12 leading-loose text-sm md:text-base text-justify\">\n      高速道路に影響を及ぼす範囲において、隣接する自治体や地権者さま等によって行われる工事や作業のことを「近接施工」といいます。この近接施工に起因する事故や事象は、高速道路施設に影響を与えるだけでなく、作業員の方や高速道路利用者への被害など、取り返しのつかない事態につながる恐れがあります。そのため、弊社が管理する高速道路に影響を及ぼす可能性がある範囲で施工される場合は、あらかじめ弊社と打ち合わせを行い、安全に作業を進めるための手続きをお願いしております。\n    </p>\n\n    <div class=\"bg-shutoko-light border-l-4 border-shutoko-green p-6 md:p-8 mb-20 rounded-r-lg shadow-sm\">\n      <div class=\"flex items-start\">\n        <svg class=\"w-6 h-6 text-shutoko-green mr-4 flex-shrink-0 mt-1\" fill=\"none\" stroke=\"currentColor\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"2\" d=\"M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z\"></path></svg>\n        <div>\n          <p class=\"text-shutoko-dark font-bold text-base md:text-lg mb-3 tracking-tight\">近接施工に関するWEBお問合せ（協議申請）について</p>\n          <p class=\"text-gray-600 text-sm md:text-base leading-relaxed\">\n            WEBお問合せフォームへのリンクは、<span class=\"font-bold text-gray-900 border-b-2 border-shutoko-green pb-0.5 mx-1\">ページ下部の「４．近接施工お問合せフォーム」</span>にございます。<br>\n            お手続きをスムーズに進めるため、まずは以下の「１」から順に、必ず内容のご確認をお願いいたします。\n          </p>\n        </div>\n      </div>\n    </div>\n\n    <div class=\"space-y-24\">\n"}];
  
  for (const file of files) {
    // Delete existing if any
    const existing = hpFolder.getFilesByName(file.name);
    while (existing.hasNext()) {
      existing.next().setTrashed(true);
    }
    
    // Create new
    const blob = Utilities.newBlob(file.content, file.mimeType, file.name);
    hpFolder.createFile(blob);
  }
  
  return "Phase 2 Component Migration Completed. Uploaded " + files.length + " files.";
